	if len(cache.retMapping) != 0 {
		err = exec.QueryRowContext(ctx, cache.query, vals...).Scan(queries.PtrsFromMapping(value, cache.retMapping)...)
	} else {
		_, err = exec.ExecContext(ctx, cache.query, vals...)
	}

	if err != nil {
		return errors.Wrap(err, "entity: unable to insert into report_actions")
	}

	if !cached {
		reportActionInsertCacheMut.Lock()
		reportActionInsertCache[key] = cache
		reportActionInsertCacheMut.Unlock()
	}

